// 把 items 数组拆成多个 item，并携带全局参数与用户提供的重量
const input = $input.first().json;
const items = Array.isArray(input.items) ? input.items : [];
return items.map(row => ({
  json: {
    jan: String(row.jan || '').trim(),
    weightGrams: typeof row.weightGrams === 'number' ? row.weightGrams : null,
    rakutenAppId: input.rakutenAppId,
    targetLanguage: input.targetLanguage,
    anthropicModel: input.anthropicModel
  }
}));

// 提取乐天第一个匹配结果；未命中返回占位。透传用户提供的重量
const items = $input.all();
const upstream = $('拆分 JAN').all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const data = items[i].json || {};
  const ctx = upstream[i]?.json || {};
  const list = data.Items || [];
  const base = {
    jan: ctx.jan,
    weightGrams: ctx.weightGrams,
    targetLanguage: ctx.targetLanguage,
    anthropicModel: ctx.anthropicModel
  };

  if (!list.length) {
    out.push({ json: { ...base, found: false, rakutenName: '', rakutenCaption: '', rakutenPrice: null, imageUrls: [], mainImage: null, shopCode: '', shopName: '', itemUrl: '' } });
    continue;
  }

  const first = list[0].Item ? list[0].Item : list[0];
  // 乐天 mediumImageUrls 带 ?_ex=128x128 缩略参数，去掉得原图
  const rawImages = (first.mediumImageUrls || []).map(x => {
    const u = typeof x === 'string' ? x : (x.imageUrl || '');
    return u.replace(/\?_ex=\d+x\d+/, '');
  });

  out.push({
    json: {
      ...base,
      found: true,
      rakutenName: first.itemName || '',
      rakutenCaption: first.itemCaption || '',
      rakutenPrice: first.itemPrice ?? null,
      imageUrls: rawImages,
      mainImage: rawImages[0] || null,
      shopCode: first.shopCode || '',
      shopName: first.shopName || '',
      itemUrl: first.itemUrl || ''
    }
  });
}

return out;

// 为每个 JAN 构造 Claude 分析请求体（不再让 Claude 抽取重量，重量由用户提供）
return $input.all().map(it => {
  const d = it.json;
  const prompt = [
    'You are a Shopee cross-border listing assistant.',
    'Analyze the following Japanese product and produce a structured listing.',
    '',
    `JAN: ${d.jan}`,
    `FoundOnRakuten: ${d.found}`,
    `ProductNameJP: ${d.rakutenName}`,
    `ProductDescriptionJP: ${d.rakutenCaption}`,
    '',
    `Output language for shopeeTitle and shopeeDescription: ${d.targetLanguage}`,
    '',
    'Return ONLY valid JSON (no markdown fence, no prose) with this exact schema:',
    '{',
    '  "brand": string|null,',
    '  "productCoreName": string,            // base product identity used for SPU grouping (brand + core line, no variant)',
    '  "variantAttributes": { "color": string|null, "size": string|null, "flavor": string|null, "other": string|null },',
    '  "dimensions": string|null,',
    '  "category": string,                    // Shopee-style category path',
    '  "keyFeatures": string[],               // 3-6 concise bullets',
    '  "shopeeTitle": string,                 // <= 100 chars, target language',
    '  "shopeeDescription": string            // 200-500 words, target language, marketing tone, Shopee-compliant'
,
    '}',
    '',
    'Rules:',
    '- If FoundOnRakuten is false or data is insufficient, set unknown fields to null and put "DATA NOT AVAILABLE - MANUAL REVIEW REQUIRED" as shopeeTitle.',
    '- Do NOT output weight; weight is supplied separately by the user.',
    '- shopeeDescription must not contain HTML tags or emoji.'
  ].join('\n');

  return {
    json: {
      ...d,
      claudeBody: {
        model: d.anthropicModel,
        max_tokens: 1500,
        messages: [{ role: 'user', content: prompt }]
      }
    }
  };
});

// 解析 Claude 响应文本为 JSON，并合并结构化字段；重量用用户提供的值
const items = $input.all();
const upstream = $('构造 Claude 分析 Body').all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const resp = items[i].json || {};
  const ctx = upstream[i]?.json || {};
  const text = resp?.content?.[0]?.text || '';

  let parsed = null;
  let parseError = null;
  try {
    const cleaned = text.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
    parsed = JSON.parse(cleaned);
  } catch (e) {
    parseError = e.message;
  }

  out.push({
    json: {
      jan: ctx.jan,
      weightGrams: ctx.weightGrams,              // 由用户提供
      found: ctx.found,
      rakutenName: ctx.rakutenName,
      rakutenCaption: ctx.rakutenCaption,
      rakutenPrice: ctx.rakutenPrice,
      shopName: ctx.shopName,
      itemUrl: ctx.itemUrl,
      mainImage: ctx.mainImage,
      imageUrls: ctx.imageUrls,
      brand: parsed?.brand ?? null,
      productCoreName: parsed?.productCoreName ?? null,
      variantAttributes: parsed?.variantAttributes ?? null,
      dimensions: parsed?.dimensions ?? null,
      category: parsed?.category ?? null,
      keyFeatures: parsed?.keyFeatures ?? [],
      shopeeTitle: parsed?.shopeeTitle ?? null,
      shopeeDescription: parsed?.shopeeDescription ?? null,
      _claudeRawText: parsed ? undefined : text,
      _parseError: parseError
    }
  });
}

return out;

// 构造 SPU 分组请求的 Claude body
const d = $input.first().json;
const slim = (d.products || []).map(p => ({
  jan: p.jan,
  brand: p.brand,
  productCoreName: p.productCoreName,
  variantAttributes: p.variantAttributes
}));

const modelFromFirst = (d.products && d.products[0] && d.products[0].anthropicModel) || 'claude-sonnet-4-6';

const prompt = [
  'You are a Shopee SPU/SKU grouping assistant.',
  'Given these products, group them into SPUs (Standard Product Units).',
  'Rule: products sharing the same brand AND the same productCoreName, differing only by variantAttributes (color/size/flavor/other), belong to the same SPU.',
  '',
  `PRODUCTS: ${JSON.stringify(slim)}`,
  '',
  'Return ONLY valid JSON (no prose) with schema:',
  '{',
  '  "spus": [',
  '    {',
  '      "spuKey": string,              // stable slug e.g. "kao-biore-uv-aqua-rich"',
  '      "brand": string|null,',
  '      "productCoreName": string,',
  '      "janList": string[]             // all JANs belonging to this SPU',
  '    }',
  '  ]',
  '}'
].join('\n');

return [{
  json: {
    products: d.products,
    spuBody: {
      model: modelFromFirst,
      max_tokens: 1000,
      messages: [{ role: 'user', content: prompt }]
    }
  }
}];

// 按 SPU 聚合 SKU，输出结构化清单
const resp = $input.first().json || {};
const ctx = $('构造 SPU 分组 Body').first().json || {};
const products = ctx.products || [];
const text = resp?.content?.[0]?.text || '';

let spus = [];
try {
  const cleaned = text.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '').trim();
  spus = (JSON.parse(cleaned).spus) || [];
} catch (e) {
  spus = products.map(p => ({
    spuKey: (p.brand || 'unknown') + '-' + (p.productCoreName || p.jan),
    brand: p.brand,
    productCoreName: p.productCoreName,
    janList: [p.jan]
  }));
}

const byJan = Object.fromEntries(products.map(p => [p.jan, p]));

const output = spus.map(spu => {
  const variants = (spu.janList || [])
    .map(j => byJan[j])
    .filter(Boolean)
    .map(p => ({
      jan: p.jan,
      variantAttributes: p.variantAttributes,
      weightGrams: p.weightGrams,
      dimensions: p.dimensions,
      rakutenName: p.rakutenName,
      rakutenPrice: p.rakutenPrice,
      mainImage: p.mainImage,
      imageUrls: p.imageUrls,
      found: p.found,
      sourceUrl: p.itemUrl
    }));

  const head = byJan[(spu.janList || [])[0]] || {};
  return {
    spuKey: spu.spuKey,
    brand: spu.brand,
    productCoreName: spu.productCoreName,
    category: head.category || null,
    shopeeTitle: head.shopeeTitle || null,
    shopeeDescription: head.shopeeDescription || null,
    keyFeatures: head.keyFeatures || [],
    mainImage: head.mainImage || null,
    variants
  };
});

return [{ json: { spus: output, rawProducts: products } }];

// 展开每个 SPU 的主图 URL 为独立 item，便于下一步并行下载
const d = $input.first().json;
return (d.spus || [])
  .filter(s => s.mainImage)
  .map(s => ({
    json: {
      spuKey: s.spuKey,
      url: s.mainImage
    }
  }));

// 把下载好的 binary 回填到每个 SPU；输出：每个 SPU 一个 item，binary.main 为主图
const downloaded = $input.all();
const spus = $('SPU 结构化输出').first().json.spus || [];

const binMap = {};
for (const it of downloaded) {
  const key = it.json?.spuKey;
  if (key && it.binary?.data) binMap[key] = it.binary.data;
}

return spus.map(spu => {
  const binary = {};
  if (binMap[spu.spuKey]) binary.main = binMap[spu.spuKey];
  return {
    json: spu,
    binary
  };
});
